const loginSchema = z.object({
  email: z.string().email('Enter a valid email'),
  password: z.string().min(1, 'Password is required'),
});

type LoginForm = z.infer<typeof loginSchema>;

export default function LoginPage() {
  const { login } = useAuth();
  const { mutateAsync: loginMutate } = useLoginMutation();
  const router = useRouter();

  const [agreed, setAgreed] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [isAnimating, setIsAnimating] = useState(true);

  const {
    control,
    handleSubmit,
    watch,
    reset,
    formState: { errors, isSubmitting },
  } = useForm<LoginForm>({
    resolver: zodResolver(loginSchema),
    defaultValues: { email: '', password: '' },
  });

  const emailVal = watch('email');
  const passwordVal = watch('password');
  const isButtonDisabled = isSubmitting || !agreed || !emailVal || !passwordVal;

  // Hydrate saved credentials on mount
  useEffect(() => {
    try {
      const raw = appStore.getString('saved_credentials');
      if (raw) {
        const saved = JSON.parse(raw) as { email: string; password: string };
        reset({ email: saved.email ?? '', password: saved.password ?? '' });
        setRememberMe(true);
      }
    } catch {
      appStore.delete('saved_credentials');
    }
  }, [reset]);

  const onSubmit = async (data: LoginForm): Promise<void> => {
    if (!agreed) {
      toast.error('Please agree to the Terms & Privacy Policy to continue.');
      return;
    }

    try {
      const response = await loginMutate({ email: data.email, password: data.password });

      if (response.token) {
        if (rememberMe) {
          appStore.set('saved_credentials', JSON.stringify({ email: data.email, password: data.password }));
        } else {
          appStore.delete('saved_credentials');
        }
        login(response.token, response.user);
        toast.success('Logged in successfully');
        router.replace('/');
      } else {
        toast.error('Login failed. Invalid credentials or empty response.');
      }
    } catch (err: unknown) {
      const apiErr = err as { message?: string };
      const message = apiErr?.message || 'Login failed. Please try again.';
      toast.error(message);
    }
  };

  const handleRememberMeChange = (checked: boolean): void => {
    setRememberMe(checked);
    if (!checked) {
      appStore.delete('saved_credentials');
    }
  };

  const handleTermsPress = (e: React.MouseEvent): void => {
    e.preventDefault();
    alert('Mock Terms, conditions and Privacy Policy URL navigation.');
  };

  const handleForgotPassword = (e: React.MouseEvent): void => {
    e.preventDefault();
    router.push(`/forgot-password${emailVal ? `?email=${encodeURIComponent(emailVal)}` : ''}`);
  };

  const handleContactUs = (e: React.MouseEvent): void => {
    e.preventDefault();
    alert('Please contact support at support@thefactory23.com');
  };

  return (
    <div className="relative flex flex-1 flex-col items-center justify-center min-h-screen bg-[#0F2B36] px-4 overflow-hidden">
      {/* Background Layer with styling matching the gradient and grid */}
      <div 
        className="absolute inset-0 z-0 bg-cover bg-center opacity-40 mix-blend-overlay"
        style={{
          backgroundImage: "url('/assets/fac-mob-login-bg-gradient.png')",
          backgroundRepeat: 'no-repeat',
        }}
      />
      <div className="absolute inset-0 z-0 bg-gradient-to-b from-[#0A1D25] via-[#0F2B36] to-[#0D252F] opacity-90" />

      {/* Main Container */}
      <div className="relative z-10 w-full max-w-sm flex flex-col items-center">
        {/* Animated Logo & Form Container */}
        <motion.div
          initial={{ y: 0, scale: 1.2 }}
          animate={{ y: 0, scale: 1 }}
          transition={{ duration: 1 }}
          className="flex flex-col items-center w-full"
        >
          <div className="mb-8 flex justify-center">
            <Logo />
          </div>

          <motion.form
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5, duration: 0.8 }}
            onSubmit={handleSubmit(onSubmit)}
            className="w-full flex flex-col px-4"
          >
            <h2 className="text-3xl font-extrabold text-[#F1F1F1] mb-6 text-center leading-normal font-sans">
              Login to Continue
            </h2>

            {/* Terms Agreement Checkbox */}
            <Checkbox
              checked={agreed}
              onChange={setAgreed}
              className="mb-5 items-start"
              label={
                <span className="text-xs text-[#FAFAFA]/80 font-sans leading-relaxed">
                  By using Factory 23, you agree to our{' '}
                  <a
                    href="#"
                    onClick={handleTermsPress}
                    className="font-semibold text-[#75ADAF] underline underline-offset-2"
                  >
                    Terms, conditions and Privacy Policy.
                  </a>
                </span>
              }
            />

            {/* Email Input */}
            <Controller
              control={control}
              name="email"
              render={({ field: { onChange, onBlur, value } }) => (
                <Input
                  placeholder="Email"
                  type="email"
                  autoComplete="email"
                  onBlur={onBlur}
                  onChange={(e) => onChange(e.target.value)}
                  value={value}
                  error={errors.email?.message}
                />
              )}
            />

            {/* Password Input */}
            <Controller
              control={control}
              name="password"
              render={({ field: { onChange, onBlur, value } }) => (
                <Input
                  placeholder="Password"
                  isPassword
                  autoComplete="current-password"
                  onBlur={onBlur}
                  onChange={(e) => onChange(e.target.value)}
                  value={value}
                  error={errors.password?.message}
                />
              )}
            />

            {/* Remember Me & Forgot Password Layout */}
            <div className="flex items-center justify-between w-full mb-8">
              <Checkbox
                checked={rememberMe}
                onChange={handleRememberMeChange}
                label="Remember Me"
                labelClassName="text-xs text-[#FAFAFA]"
              />
              <a
                href="#"
                onClick={handleForgotPassword}
                className="text-xs font-semibold text-[#FAFAFA] hover:underline"
              >
                Forgot Password?
              </a>
            </div>

            {/* Login Button */}
            <button
              type="submit"
              disabled={isButtonDisabled}
              className={`w-full h-[51px] rounded-[30px] bg-[#75ADAF] hover:bg-[#66989A] text-white font-semibold flex items-center justify-center transition-all duration-200 shadow-md ${
                isButtonDisabled ? 'opacity-60 cursor-not-allowed' : 'active:scale-95'
              }`}
            >
              {isSubmitting ? (
                <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                'Log In'
              )}
            </button>

            {/* Footer Contact Link */}
            <div className="mt-6 flex justify-center text-center">
              <span className="text-xs text-[#FAFAFA] font-sans">
                Don’t have an account?{' '}
                <a href="#" onClick={handleContactUs} className="font-semibold underline">
                  Contact Us.
                </a>
              </span>
            </div>
          </motion.form>
        </motion.div>
      </div>
    </div>
  );
}
